=/**
 * EXTRATOR + NORMALIZADOR UNIVERSAL - BANCO INTER (TEXTO PURO)
 * - Extrai transações de texto corrido / sem markdown
 * - Normaliza para o formato final do banco de dados
 */

// ========================================
// 1. DADOS DA CONTA
// ========================================

let accountId = "";
let bankName = "";

try {
  const webhook = $('Recebe link do Supabase Storage').first().json;
  const webData = webhook.body || webhook;

  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
} catch (e) {
  bankName = "Banco";
}

// ========================================
// 2. CONFIGURAÇÃO DE MESES
// ========================================

const meses = {
  "janeiro": "01",
  "fevereiro": "02",
  "março": "03",
  "abril": "04",
  "maio": "05",
  "junho": "06",
  "julho": "07",
  "agosto": "08",
  "setembro": "09",
  "outubro": "10",
  "novembro": "11",
  "dezembro": "12"
};

// ========================================
// 3. EXTRAÇÃO DAS TRANSAÇÕES (AJUSTADO PARA TEXTO PURO)
// ========================================

const inputData = $input.all();
const listaBruta = [];

for (const item of inputData) {

  // Tenta pegar texto de qualquer campo possível
  const textoBruto =
    item.json.markdown ||
    item.json.extractedText ||
    item.json.text ||
    "";

  // Caso já venha estruturado
  if (Array.isArray(item.json.output)) {
    listaBruta.push(...item.json.output);
    continue;
  }

  const linhas = textoBruto.split('\n');

  let dataVigente = null;

  // Regex para capturar transações em texto corrido (Ex: Pix recebido: "NOME" R$ 14,00)
  const regexTransacao = /(Pix recebido:|Pix enviado:|Pagamento efetuado:|Credito liberado:|Compra no debito:|Credito Evento B3:|Transferência|Pagamento|Compra|Tarifa)\s+(.+?)\s+(-?\s*R\$\s*[\d.,]+)/i;

  for (let linha of linhas) {

    linha = linha.trim();

    if (!linha) continue;

    // ========================================
    // IGNORA LINHAS IRRELEVANTES
    // ========================================

    if (
      linha.includes("SAC:") ||
      linha.includes("Ouvidoria:") ||
      linha.includes("Deficiência") ||
      linha.includes("Fale com a gente")
    ) {
      continue;
    }

    // ========================================
    // DETECTA CABEÇALHO DE DATA
    // Ex: "16 de Janeiro de 2026" ou "3 de Janeiro de 2026"
    // ========================================

    const regexData = /(\d{1,2})\s+de\s+([a-zA-Zçãó]+)\s+de\s+(\d{4})/i;

    const matchData = linha.match(regexData);

    if (matchData) {

      const dia = matchData[1].padStart(2, '0');
      const mesTexto = matchData[2].toLowerCase();
      const ano = matchData[3];

      const mes = meses[mesTexto] || "01";

      dataVigente = `${dia}/${mes}/${ano}`;

      continue;
    }

    // ========================================
    // CAPTURA TRANSAÇÃO EM TEXTO CORRIDO
    // ========================================

    const matchTransacao = linha.match(regexTransacao);

    if (matchTransacao && dataVigente) {
      const indicadorTipo = matchTransacao[1]; // Ex: "Pix recebido:"
      const descricaoBruta = matchTransacao[2].replace(/"/g, '').trim(); // Remove aspas extras do nome
      const valorBruto = matchTransacao[3];

      // Junta o tipo da operação ao nome para criar uma descrição amigável e fiel
      const descricaoCompleta = `${indicadorTipo} ${descricaoBruta}`;

      // Normaliza o valor para float
      let valorTexto = valorBruto
        .replace(/[-R$\s]/g, '')
        .replace(/\./g, '')
        .replace(',', '.');

      let valor = parseFloat(valorTexto) || 0;

      // Define o sinal contábil com base no tipo de termo extraído
      const ehDespesa = indicadorTipo.toLowerCase().includes('enviado') || 
                        indicadorTipo.toLowerCase().includes('pagamento') || 
                        indicadorTipo.toLowerCase().includes('compra') || 
                        indicadorTipo.toLowerCase().includes('tarifa');

      const sinal = ehDespesa ? '-' : '+';

      valor = Math.abs(valor);

      if (descricaoBruta) {
        listaBruta.push({
          d: dataVigente,
          t: descricaoCompleta,
          v: valor,
          s: sinal
        });
      }
    }
  }
}

// ========================================
// 4. NORMALIZAÇÃO FINAL
// ========================================

const anoAtual = new Date().getFullYear();

const final = listaBruta.map((item, index) => {

  const desc = (item.t || "")
    .toString()
    .toUpperCase()
    .trim();

  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') {
    v = v
      .replace(/[R$\s]/ig, '')
      .replace(',', '.');
  }

  let valorFinal = parseFloat(v) || 0;

  // ========================================
  // APLICA SINAL
  // ========================================

  if (
    item.s === "-" ||
    item.s === "despesa"
  ) {
    valorFinal = -Math.abs(valorFinal);
  } else {
    valorFinal = Math.abs(valorFinal);
  }

  // ========================================
  // NORMALIZA DATA
  // dd/mm/yyyy -> yyyy-mm-dd
  // ========================================

  let dataF = item.d || "";

  if (dataF.includes('/')) {

    const p = dataF.split('/');

    dataF = `${p[2] || anoAtual}-${p[1].padStart(2, '0')}-${p[0].padStart(2, '0')}T12:00:00`;
  }

  // ========================================
  // DEFINE TIPO
  // ========================================

  const categoriasNeutras = [
    "reembolsos",
    "estorno",
    "pagamento-fatura-cartao",
    "transferencia-mesma-titularidade",
    "despesas-reembolsaveis",
    "reserva-emergencia",
    "projetos-vida",
    "independencia-financeira"
  ];

  const tipo =
    valorFinal < 0
      ? "despesa"
      : categoriasNeutras.includes(item.c)
        ? "neutro"
        : "receita";

  // ========================================
  // RETORNO FINAL
  // ========================================

  return {
    json: {
      account_id: accountId,
      Conta: bankName,

      Data_lancamento: dataF,
      Data_pagamento: dataF,

      Descricao: desc,

      Valor: valorFinal,

      Tipo: tipo,

      Categoria: item.c || "outros-gv",

      id_conciliacao: `${desc.replace(/[^A-Z0-9]/g, '')}-${dataF.split('T')[0]}-${Math.abs(valorFinal)}-${index}`
    }
  };

});

return final;

=/**
 * EXTRATOR BRADESCO
 * * Formato do extrato:
 * - Tabela com colunas: Data | Histórico | Docto. | Crédito (R$) | Débito (R$) | Saldo (R$)
 * - A data aparece apenas na primeira transação do dia (células mescladas verticalmente no PDF)
 * - O campo "Histórico" pode ter duas linhas: tipo da transação + descrição/nome
 * Ex: "TRANSFERENCIA PIX\nREM: JOAQUIM BENTO FERREIR 01/04"
 * - REM = remetente (crédito), DES = destinatário (débito)
 * - Crédito e Débito são colunas separadas (não há sinal no valor)
 * - Linhas de cabeçalho, totais e saldo inicial são ignoradas
 */

// ========================================
// 1. DADOS DA CONTA
// ========================================

let accountId = "";
let bankName = "Bradesco";

try {
  const webhook = $('Recebe link do Supabase Storage').first().json;
  const webData = webhook.body || webhook;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Bradesco";
} catch (e) {
  bankName = "Bradesco";
}

// ========================================
// 2. HELPERS
// ========================================

/**
 * Converte "dd/mm/yyyy" → "yyyy-mm-ddT12:00:00"
 */
function normalizarData(dataStr) {
  if (!dataStr) return "";
  const p = dataStr.trim().split('/');
  if (p.length !== 3) return dataStr;
  return `${p[2]}-${p[1].padStart(2, '0')}-${p[0].padStart(2, '0')}T12:00:00`;
}

/**
 * Converte valor brasileiro "1.234,56" → número float
 * Remove R$, espaços, pontos de milhar e troca vírgula por ponto
 */
function normalizarValor(valorStr) {
  if (!valorStr) return 0;
  const limpo = valorStr
    .toString()
    .replace(/[R$\s]/g, '')
    .replace(/\./g, '')
    .replace(',', '.');
  return parseFloat(limpo) || 0;
}

/**
 * Verifica se uma linha é cabeçalho, rodapé ou linha irrelevante
 */
function linhaIrrelevante(linha) {
  const irrelevantes = [
    /^Data\s+Histórico/i,
    /^Crédito\s*\(R\$\)/i,
    /^Débito\s*\(R\$\)/i,
    /^Saldo\s*\(R\$\)/i,
    /^Docto\./i,
    /^Total\b/i,
    /^COD\.\s*LANC\.\s*0/i,
    /^Bradesco\s+Celular/i,
    /^Data:\s*\d{2}\/\d{2}\/\d{4}/i,
    /^Nome:/i,
    /^Extrato de:/i,
    /^Agência:/i,
    /^Folha:/i,
    /SAC:/i,
    /Ouvidoria:/i,
    /Deficiência/i,
    /Fale com a gente/i,
  ];
  return irrelevantes.some(r => r.test(linha.trim()));
}

/**
 * Tenta identificar uma data no formato dd/mm/yyyy
 */
function extrairData(texto) {
  const match = texto.match(/^(\d{1,2})\/(\d{2})\/(\d{4})$/);
  if (match) return texto.trim();
  return null;
}

// ========================================
// 3. PARSING DO TEXTO DO PDF
// ========================================

const inputData = $input.all();
const transacoes = [];

// DATA VIGENTE GLOBAL: Mantém a data entre as páginas do PDF
let dataVigente = null;

for (const item of inputData) {

  const textoBruto =
    item.json.markdown ||
    item.json.extractedText ||
    item.json.text ||
    "";

  // Caso já venha pré-processado como array
  if (Array.isArray(item.json.output)) {
    transacoes.push(...item.json.output);
    continue;
  }

  const linhas = textoBruto.split('\n');

  // ----------------------------------------
  // DETECTA SE É FORMATO TABELA MARKDOWN
  // ----------------------------------------
  const temPipes = linhas.some(l => l.trim().startsWith('|') && l.includes('|'));

  if (temPipes) {
    // ========================================
    // PARSER: TABELA MARKDOWN COM PIPES
    // ========================================
    for (let linha of linhas) {
      linha = linha.trim();
      if (!linha) continue;
      if (linhaIrrelevante(linha)) continue;

      if (/^\|[\s\-|]+\|$/.test(linha)) continue;
      if (/\|\s*Data\s*\|/i.test(linha)) continue;
      if (/\|\s*Histórico\s*\|/i.test(linha)) continue;

      if (!linha.startsWith('|')) continue;

      const cols = linha
        .split('|')
        .map(c => c.trim())
        .filter((_, i, arr) => i > 0 && i < arr.length - 1);

      if (cols.length < 4) continue;

      const [colData, colHistorico, colDocto, colCredito, colDebito] = cols;

      const dataCandidata = extrairData(colData);
      if (dataCandidata) {
        dataVigente = dataCandidata;
      }

      if (!colHistorico) continue;
      if (/^Saldo total/i.test(colHistorico)) continue;
      if (/^Total\b/i.test(colHistorico)) continue;
      if (/^COD\. LANC/i.test(colHistorico)) continue;

      const credito = normalizarValor(colCredito);
      const debito = normalizarValor(colDebito);

      if (credito === 0 && debito === 0) continue;
      if (!dataVigente) continue;

      const isCredito = credito > 0;
      const valor = isCredito ? credito : debito;

      // Limpa a descrição removendo aspas e o número do documento (7 dígitos)
      let historicoLimpo = colHistorico
        .replace(/"/g, '')
        .replace(/\b\d{7}\b/g, '') 
        .replace(/\s+/g, ' ')      
        .trim();

      transacoes.push({
        d: dataVigente,
        t: historicoLimpo,
        v: valor,
        s: isCredito ? '+' : '-',
        doc: colDocto || "",
      });
    }

  } else {
    // ========================================
    // PARSER: TEXTO PURO / COLUNAS ALINHADAS
    // ========================================
    const VALOR_RE = /\d{1,3}(?:\.\d{3})*,\d{2}/g;
    const DATA_RE = /(\d{2}\/\d{2}\/\d{4})/;
    const LINHA_TRANSACAO_RE = /(\d{1,3}(?:\.\d{3})*,\d{2})\s*$/;

    let linhaAnterior = "";

    for (let i = 0; i < linhas.length; i++) {
      let linha = linhas[i];
      const linhaLimpa = linha ? linha.trim() : "";

      if (!linhaLimpa) { linhaAnterior = ""; continue; }
      if (linhaIrrelevante(linhaLimpa)) { linhaAnterior = ""; continue; }

      // Detecta data na linha
      const matchData = linhaLimpa.match(DATA_RE);
      if (matchData) {
        dataVigente = matchData[1];
      }

      // Verifica se a linha termina com valor monetário
      if (!LINHA_TRANSACAO_RE.test(linhaLimpa)) {
        linhaAnterior = linhaLimpa;
        continue;
      }

      // Extrai todos os valores monetários da linha
      const valores = [];
      let match;
      const re = new RegExp(VALOR_RE.source, 'g');
      while ((match = re.exec(linhaLimpa)) !== null) {
        valores.push(normalizarValor(match[0]));
      }

      if (valores.length === 0) { linhaAnterior = ""; continue; }
      if (!dataVigente) { linhaAnterior = ""; continue; }

      if (/^COD\. LANC\. 0/i.test(linhaLimpa)) { internetAnterior = ""; continue; }
      if (/^Total\b/i.test(linhaLimpa)) { linhaAnterior = ""; continue; }

      // Começa a limpar a descrição
      let descricao = linhaLimpa;

      // 1. Remove as aspas e os delimitadores de CSV/JSON residuais que juntam as colunas
      descricao = descricao.replace(/["]/g, ' ');

      // 2. Remove a data
      descricao = descricao.replace(DATA_RE, '');

      // 3. CORREÇÃO DA REGEX: Remove de forma agressiva qualquer número de 6 a 8 dígitos (Docto)
      // que esteja solto ou separado por vírgulas/espaços no meio ou fim do texto.
      descricao = descricao.replace(/\b\d{6,8}\b/g, ' ');

      // 4. Remove os valores monetários que sobraram
      descricao = descricao.replace(/\d{1,3}(?:\.\d{3})*,\d{2}/g, ' ');

      // Limpa espaços duplicados gerados pelos replaces
      descricao = descricao.replace(/\s+/g, ' ').trim();

      // Adiciona complemento da linha anterior se for parte do histórico
      if (linhaAnterior && !LINHA_TRANSACAO_RE.test(linhaAnterior) && !linhaAnterior.match(DATA_RE)) {
        // Limpa aspas e o documento da linha anterior também, caso ela tenha trazido resíduos
        let antLimpa = linhaAnterior.replace(/["]/g, ' ').replace(/\b\d{6,8}\b/g, ' ').trim();
        descricao = `${antLimpa} ${descricao}`.trim();
      }

      // Re-higieniza espaços finais
      descricao = descricao.replace(/\s+/g, ' ').trim();

      // Determina crédito ou débito
      let isCredito = false;
      let valorTransacao = 0;

      if (/\bREM:/i.test(descricao) || /\bREM\b/i.test(linhaAnterior || "")) {
        isCredito = true;
      } else if (/\bDES:/i.test(descricao) || /\bDES\b/i.test(linhaAnterior || "")) {
        isCredito = false;
      } else if (/RESG\/VENCTO CDB|RENTAB\.INVEST|DEVOLUCAO PIX/i.test(descricao)) {
        isCredito = true;
      } else if (/APLICACAO CDB/i.test(descricao)) {
        isCredito = false;
      } else {
        isCredito = false;
      }

      if (valores.length >= 2) {
        valorTransacao = valores[valores.length - 2];
      } else if (valores.length === 1) {
        linhaAnterior = linhaLimpa;
        continue;
      }

      if (valorTransacao === 0) { linhaAnterior = ""; continue; }

      transacoes.push({
        d: dataVigente,
        t: descricao,
        v: valorTransacao,
        s: isCredito ? '+' : '-',
      });

      linhaAnterior = linhaLimpa;
    }
  }
}

// ========================================
// 4. NORMALIZAÇÃO FINAL
// ========================================

const anoAtual = new Date().getFullYear();

const final = transacoes.map((item, index) => {

  const desc = (item.t || "")
    .toString()
    .toUpperCase()
    .replace(/\s+/g, ' ')
    .trim();

  let valorFinal = parseFloat(item.v) || 0;

  if (item.s === '-' || item.s === 'despesa') {
    valorFinal = -Math.abs(valorFinal);
  } else {
    valorFinal = Math.abs(valorFinal);
  }

  const dataF = normalizarData(item.d) || `${anoAtual}-01-01T12:00:00`;

  const categoriasNeutras = [
    "reembolsos",
    "estorno",
    "pagamento-fatura-cartao",
    "transferencia-mesma-titularidade",
    "despesas-reembolsaveis",
    "reserva-emergencia",
    "projetos-vida",
    "independencia-financeira",
  ];

  const tipo =
    valorFinal < 0
      ? "despesa"
      : categoriasNeutras.includes(item.c || "")
        ? "neutro"
        : "receita";

  return {
    json: {
      account_id: accountId,
      Conta: bankName,

      Data_lancamento: dataF,
      Data_pagamento: dataF,

      Descricao: desc,

      Valor: valorFinal,

      Tipo: tipo,

      Categoria: item.c || "outros-gv",

      id_conciliacao: `${desc}-${valorFinal}-${index}`,

      _doc: item.doc || "",
      _data_original: item.d || "",
    }
  };
});

return final;

=/**
 * EXTRATOR + NORMALIZADOR - BANCO DO BRASIL (ADAPTADO AO PDF REAL)
 * Formato: Extrato de Conta Corrente BB via PDF Text
 */

// ========================================
// 1. DADOS DA CONTA
// ========================================
let accountId = "";
let bankName = "Banco do Brasil";

try {
  const webhook = $('Recebe link do Supabase Storage').first().json;
  const webData = webhook.body || webhook;
  accountId = webData.accountId || "";
  bankName  = webData.bankName  || "Banco do Brasil";
} catch (e) {
  bankName = "Banco do Brasil";
}

// ========================================
// 2. REGEX ULTRA-FLEXÍVEL (Captura Data, Valor e Sinal na mesma linha)
// ========================================
const REGEX_TRANSACAO_COMBINADA = /(\d{2}\/\d{2}\/\d{4})\s+([\d.,]+)\s*\(?([+-])\)?/;

// ========================================
// 3. LINHAS IGNORAR
// ========================================
const LINHAS_IGNORAR = [
  "Extrato de Conta Corrente",
  "Cliente ",
  "Agência:",
  "Lançamentos",
  "Dia Lote",
  "SAC:",
  "Ouvidoria:",
  "Saldo Anterior",
  "Saldo do dia",
  "S A L D O",
  "Informações Adicionais",
  "Tarifa",
  "Limite"
];

const deveIgnorar = (linha) => {
  return LINHAS_IGNORAR.some(p => linha.includes(p));
};

// ========================================
// 4. PARSE PRINCIPAL
// ========================================
const listaBruta = [];

for (const item of inputData) {
  if (item.json && Array.isArray(item.json.output)) {
    listaBruta.push(...item.json.output);
    continue;
  }

  const textoBruto = item.markdown || item.extractedText || item.text || (item.json ? item.json.markdown : "") || "";
  if (!textoBruto) continue;

  // UNIFICA LINHAS ESPARRAMADAS DO FORMATO NOVO
  const linhasRaw = textoBruto.split('\n').map(l => l.trim()).filter(Boolean);
  const linhas = [];
  let linhaConstruida = "";

  for (const l of linhasRaw) {
    if (/^["|]*\d{2}\/\d{2}\/\d{4}/.test(l)) {
      if (linhaConstruida) linhas.push(linhaConstruida.replace(/["|]/g, '').replace(/\s+/g, ' ').trim());
      linhaConstruida = l;
    } else if (linhaConstruida) {
      linhaConstruida += " " + l;
    }
  }
  if (linhaConstruida) linhas.push(linhaConstruida.replace(/["|]/g, '').replace(/\s+/g, ' ').trim());

  // LOOP DE PROCESSAMENTO
  for (let i = 0; i < linhas.length; i++) {
    const linhaAtual = linhas[i];

    if (deveIgnorar(linhaAtual)) continue;

    // REGEX MONETÁRIA ESTRITA CONTRA DOCUMENTOS LONGOS
    const match = linhaAtual.match(/(\d{2}\/\d{2}\/\d{4})(.*?)(\b\d+(?:\.\d{3})*,\d{2}\b|\b\d+(?:,\d{3})*\.\d{2}\b|\b\d+,\d{2}\b|\b\d+\.\d{2}\b)\s*\(?([+-CDcd])\)?/);

    if (match) {
      const dataPt = match[1];
      const historicoDetectado = match[2];
      let valorTexto = match[3];
      const sinalBruto = match[4];

      // Padroniza o sinal (C/D) para o padrão original (+/-) esperado pelo seu n8n
      const sinal = (sinalBruto.toUpperCase() === 'D' || sinalBruto === '-') ? '-' : '+';

      // Corrige pontos decimais se o PDF vier no padrão americano (ex: 685.00 -> 685,00)
      if (valorTexto.includes('.') && !valorTexto.includes(',')) {
        let partes = valorTexto.split('.');
        let cents = partes.pop();
        valorTexto = partes.join('') + ',' + cents;
      }

      // Formata a data (DD/MM/AAAA -> AAAA-MM-DD)
      const [dia, mes, ano] = dataPt.split('/');
      const dataVigente = `${ano}-${mes}-${dia}`;

      // Formata o valor numérico
      const valorNum = parseFloat(valorTexto.replace(/\./g, '').replace(',', '.')) || 0;

      // tenta pegar da própria linha
      let historico = historicoDetectado
        .replace(/^[\s,,;|-]+/, '')
        .replace(/[\s,,;|-]+$/, '')
        .trim();

      // remove lote/documento
      historico = historico
        .replace(/^\d+\s+\d+\s*/, '')
        .replace(/^\d+\s*/, '')
        .trim();

      // se ficou vazio OU virou só número, pega a próxima linha (Histórico real)
      if ((!historico || /^\d+$/.test(historico)) && i + 1 < linhas.length) {
        historico = linhas[i + 1].trim();
      }

      // concatena detalhe da linha seguinte (horário/nome)
      if (
        i + 2 < linhas.length &&
        /^\d{2}\/\d{2}\s/.test(linhas[i + 2])
      ) {
        historico += " " + linhas[i + 2].trim();
      }

      // Limpa números de documentos/lotes repetitivos no início do histórico
      historico = historico
        .replace(/^\d{4,5}\s+\d{4,20}\s+/, '')
        .replace(/^\d{4,5}\s+/, '')
        .replace(/^-/, '') 
        .trim();

      // Remove resíduos de colunas de saldo acumulado que possam ter sobrado no fim da descrição
      historico = historico.replace(/\s*[\d,.]+\s*[+-CDcd]\s*$/, '').trim();

      // Evita salvar linhas de saldo remanescentes
      if (historico && !/saldo/i.test(historico) && !deveIgnorar(historico)) {
        listaBruta.push({
          d: dataVigente,
          t: historico,
          v: valorNum,
          s: sinal,
          c: "outros-gv"
        });
      }
    }
  }
}

// ========================================
// 5. NORMALIZAÇÃO FINAL (SEU ORIGINAL INTACTO)
// ========================================
const anoAtual = new Date().getFullYear();

const final = listaBruta.map((item, index) => {
  const desc = String(item.t || "").toUpperCase().replace(/\s+/g, ' ').trim();

  let valorFinal = parseFloat(item.v) || 0;
  valorFinal = item.s === "-" ? -Math.abs(valorFinal) : Math.abs(valorFinal);

  const tipo = valorFinal < 0 ? "despesa" : "receita";
  const dataF = item.d ? item.d + "T12:00:00" : `${anoAtual}-01-01T12:00:00`;
  const idLimpo = `${desc.replace(/[^A-Z0-9]/g, '')}-${dataF.split('T')[0]}-${Math.abs(valorFinal)}-${index}`;

  return {
    json: {
      account_id: accountId,
      Conta: bankName,
      Data_lancamento: dataF,
      Data_pagamento:  dataF,
      Descricao: desc,
      Valor:      valorFinal,
      Tipo:        tipo,
      Categoria:  item.c || "outros-gv",
      id_conciliacao: idLimpo,
    }
  };
});

return final;

