parameters.jsCode:
// 1. Buscamos o binário diretamente do nó que processou o arquivo original
// Se o nó que criou o binário tiver outro nome, ajuste 'Code in JavaScript10' abaixo
const nodeComArquivo = 'Code in JavaScript6'; 

let binaryData;
try {
    binaryData = await this.helpers.getBinaryDataBuffer(0, 'data', nodeComArquivo);
} catch (e) {
    // Caso o nome acima esteja diferente, tentamos pegar do que entrar no nó
    binaryData = await this.helpers.getBinaryDataBuffer(0, 'data');
}

if (!binaryData) {
    throw new Error("Arquivo binário não encontrado. Verifique se o nome do nó de origem está correto.");
}

const rawText = binaryData.toString('utf8');

// 2. O restante do seu processamento OFX
const trnRegex = /<STMTTRN>([\s\S]*?)<\/STMTTRN>/g;
const transactions = [];
let match;

while ((match = trnRegex.exec(rawText)) !== null) {
    const block = match[1];

    const getValue = (tag) => {
        const r = new RegExp(`<${tag}>([^<\\n\\r]+)`, 'i');
        const m = block.match(r);
        return m ? m[1].trim() : null;
    };

    const dateRaw = getValue('DTPOSTED');
    const amountStr = getValue('TRNAMT');
    const amount = parseFloat(amountStr);

    if (dateRaw && amountStr) {
        transactions.push({
            json: {
                d: `${dateRaw.substring(6,8)}/${dateRaw.substring(4,6)}/${dateRaw.substring(0,4)}`,
                t: getValue('MEMO') || getValue('NAME') || "TRANSACAO OFX",
                v: Math.abs(amount),
                s: amount < 0 ? '-' : '+',
                c: null
            }
        });
    }
}

return transactions;

/**
 * NORMALIZADOR UNIVERSAL (PEGA TUDO O QUE CHEGAR)
 */
// 1. DADOS DA CONTA
let accountId = "";
let bankName = "";
try {
  const webhook = $('Recebe link do Supabase Storage').first().json;
  const webData = webhook.body || webhook;
  accountId = webData.accountId || "";
  bankName = webData.bankName || "Banco";
} catch (e) { bankName = "Banco"; }
// 2. CAPTURA DE DADOS (ABERTURA DE ENVELOPE)
let listaBruta = [];
const incomingData = $input.all();
for (const item of incomingData) {
  const data = item.json;

  // Tenta encontrar a lista de transações em qualquer lugar
  let alvo = data.output !== undefined ? data.output : data;

  // NOVO: se vier como string (sem Output Parser, o chainLlm devolve texto puro
  // em $json.text ou dentro do próprio campo output), faz o parse manual aqui.
  if (typeof alvo === 'string') {
    let raw = alvo.trim().replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
    try { alvo = JSON.parse(raw); } catch (e) {
      throw new Error(`Falha ao fazer parse do JSON: ${e.message}\nTrecho: ${raw.slice(0, 300)}`);
    }
  } else if (alvo === data && typeof data.text === 'string') {
    let raw = data.text.trim().replace(/^```json\s*/i, '').replace(/```$/i, '').trim();
    try { alvo = JSON.parse(raw); } catch (e) {
      throw new Error(`Falha ao fazer parse do JSON: ${e.message}\nTrecho: ${raw.slice(0, 300)}`);
    }
  }

  if (Array.isArray(alvo)) {
    listaBruta = listaBruta.concat(alvo);
  } else if (typeof alvo === 'object' && (alvo.t || alvo.d)) {
    listaBruta.push(alvo);
  }
}
// 3. MAPEAMENTO
const anoAtual = new Date().getFullYear();
const final = listaBruta.map((item, index) => {
  const desc = (item.t || "").toString().toUpperCase().trim();
  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') v = v.replace(/[R$\s]/ig, '').replace(',', '.');
  let valorFinal = parseFloat(v) || 0;

  if (item.s === "-" || item.s === "despesa") valorFinal = -Math.abs(valorFinal);
  else valorFinal = Math.abs(valorFinal);
  let dataF = item.d || "";
  if (dataF.includes('/')) {
    let p = dataF.split('/');
    dataF = `${p[2] || anoAtual}-${p[1].padStart(2,'0')}-${p[0].padStart(2,'0')}T12:00:00`;
  }
  return {
    json: {
      account_id: accountId,
      Conta: bankName,
      Data_lancamento: dataF,
      Data_pagamento: dataF,
      Descricao: desc,
      Valor: valorFinal,
      Tipo: valorFinal < 0 ? "despesa" : (["reembolsos", "estorno","pagamento-fatura-cartao", "transferencia-mesma-titularidade", "despesas-reembolsaveis", "reserva-emergencia", "projetos-vida", "independencia-financeira"].includes(item.c) ? "neutro" : "receita"),
      Categoria: item.c || "outros-gv",
      id_conciliacao: `${desc}-${valorFinal}-${index}`
    }
  };
});
return final;

