  let v = item.v !== undefined ? item.v : 0;

  if (typeof v === 'string') {
    v = v
      .replace(/[R$\s]/ig, '')
      .replace(',', '.');
  }

  let valorFinal = parseFloat(v) || 0;

  // ========================================
  // APLICA SINAL
  // ========================================

  if (
    item.s === "-" ||
    item.s === "despesa"
  ) {
    valorFinal = -Math.abs(valorFinal);
  } else {
    valorFinal = Math.abs(valorFinal);
  }

  // ========================================
  // NORMALIZA DATA
  // dd/mm/yyyy -> yyyy-mm-dd
  // ========================================

  let dataF = item.d || "";

  if (dataF.includes('/')) {

    const p = dataF.split('/');

    dataF = `${p[2] || anoAtual}-${p[1].padStart(2, '0')}-${p[0].padStart(2, '0')}T12:00:00`;
  }

  // ========================================
  // DEFINE TIPO
  // ========================================

  const categoriasNeutras = [
    "reembolsos",
    "estorno",
    "pagamento-fatura-cartao",
    "transferencia-mesma-titularidade",
    "despesas-reembolsaveis",
    "reserva-emergencia",
    "projetos-vida",
    "independencia-financeira"
  ];

  const tipo =
    valorFinal < 0
      ? "despesa"
      : categoriasNeutras.includes(item.c)
        ? "neutro"
        : "receita";

  // ========================================
  // RETORNO FINAL
  // ========================================

  return {
    json: {
      account_id: accountId,
      Conta: bankName,

